using System;
using System.Linq;
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

namespace QuickCode.Demo.Infrastructure.Web.Extensions;

public static class CorsExtensions
{
    /// <summary>
    /// Applies origin-restricted CORS from <c>CorsSettings:AllowOrigins</c>.
    /// Skips <see cref="CorsExtensions.UseCors"/> when no origins are configured
    /// (avoids the runtime throw from empty <c>WithOrigins</c>).
    /// </summary>
    public static IApplicationBuilder UseQuickCodeCors(
        this IApplicationBuilder app,
        IConfiguration configuration)
    {
        var origins = configuration.GetSection("CorsSettings:AllowOrigins").Get<string[]>()
            ?.Where(static o => !string.IsNullOrWhiteSpace(o))
            .Select(static o => o.Trim())
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToArray()
            ?? [];

        if (origins.Length == 0)
        {
            app.ApplicationServices.GetService<ILoggerFactory>()
                ?.CreateLogger("QuickCode.Cors")
                .LogWarning("CorsSettings:AllowOrigins is missing or empty; CORS middleware was not registered");
            return app;
        }

        return app.UseCors(policy => policy
            .AllowAnyHeader()
            .AllowAnyMethod()
            .WithOrigins(origins)
            .SetIsOriginAllowedToAllowWildcardSubdomains());
    }
}
